/**
 * FavoriteButton
 *
 * Toggle-style icon button for “favorite / bookmark / like” interactions.
 * The parent owns the state; this component simply renders the UI and reports
 * toggles via `onToggle`.
 *
 * @example
 * ```tsx
 * <FavoriteButton
 *   isFavorited={isSaved}
 *   onToggle={(next) => setIsSaved(next)}
 *   favoriteType="bookmark"
 * />
 * ```
 */

'use client';
import * as React from 'react';
import IconButton from '@mui/material/IconButton';
import type { IconButtonProps } from '@mui/material/IconButton';
import Tooltip from '@mui/material/Tooltip';
import FavoriteIcon from '@mui/icons-material/Favorite';
import FavoriteBorderIcon from '@mui/icons-material/FavoriteBorder';
import BookmarkIcon from '@mui/icons-material/Bookmark';
import BookmarkBorderIcon from '@mui/icons-material/BookmarkBorder';
import ThumbUpIcon from '@mui/icons-material/ThumbUp';
import ThumbUpOutlinedIcon from '@mui/icons-material/ThumbUpOutlined';

export type FavoriteType = 'heart' | 'bookmark' | 'like';

/** Props for {@link FavoriteButton}. */
export interface FavoriteButtonProps extends Omit<IconButtonProps, 'onClick'> {
  isFavorited?: boolean;
  onToggle: (isFavorited: boolean, itemId?: string) => void;
  itemId?: string;
  favoriteType?: FavoriteType;
  showTooltip?: boolean;
  tooltipText?: { favorited: string; unfavorited: string };
}

const FavoriteButton: React.FC<FavoriteButtonProps> = ({
  isFavorited = false,
  onToggle,
  itemId,
  favoriteType = 'heart',
  showTooltip = true,
  tooltipText,
  sx,
  ...rest
}) => {

  //

 const favorited = isFavorited;

const handleToggle = () => {
  onToggle(!favorited, itemId);
};

  const getIcons = () => {
    switch (favoriteType) {
      case 'bookmark':
        return {
          filled: <BookmarkIcon />,
          outlined: <BookmarkBorderIcon />,
          color: '#1976d2',
        };
      case 'like':
        return {
          filled: <ThumbUpIcon />,
          outlined: <ThumbUpOutlinedIcon />,
          color: '#1976d2',
        };
      default:
        return {
          filled: <FavoriteIcon />,
          outlined: <FavoriteBorderIcon />,
          color: '#f44336',
        };
    }
  };

  const getTooltipText = () => {
    if (tooltipText) {
      return favorited ? tooltipText.favorited : tooltipText.unfavorited;
    }

    switch (favoriteType) {
      case 'bookmark':
        return favorited ? 'Remove bookmark' : 'Add bookmark';
      case 'like':
        return favorited ? 'Unlike' : 'Like';
      default:
        return favorited ? 'Remove from favorites' : 'Add to favorites';
    }
  };

 
  const icons = getIcons();
  const currentIcon = favorited ? icons.filled : icons.outlined;

  const button = (
    <IconButton
      onClick={handleToggle}
      aria-label={getTooltipText()}
      sx={{
        color: favorited ? icons.color : 'action.active',
        transition: 'all 0.2s ease-in-out',
        '&:hover': {
          transform: 'scale(1.1)',
          color: icons.color,
        },
        ...sx,
      }}
      {...rest}
    >
      {currentIcon}
    </IconButton>
  );

  if (showTooltip) {
    return <Tooltip title={getTooltipText()}>{button}</Tooltip>;
  }

  return button;
};

export default FavoriteButton;
